2023: func (a *Server) checkU2F(ctx context.Context, user string, res u2f.AuthenticateChallengeResponse, u2fStorage u2f.AuthenticationStorage) error {
2024: 	devs, err := a.GetMFADevices(ctx, user)
2025: 	if err != nil {
2026: 		return trace.Wrap(err)
2027: 	}
2028: 	for _, dev := range devs {
2029: 		u2fDev := dev.GetU2F()
2030: 		if u2fDev == nil {
2031: 			continue
2032: 		}
2033: 
2034: 		// U2F passes key handles around base64-encoded, without padding.
2035: 		kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
2036: 		if kh != res.KeyHandle {
2037: 			continue
2038: 		}
2039: 		if err := u2f.AuthenticateVerify(ctx, u2f.AuthenticateVerifyParams{
2040: 			Dev:        dev,
2041: 			Resp:       res,
2042: 			Storage:    u2fStorage,
2043: 			StorageKey: user,
2044: 			Clock:      a.clock,
2045: 		}); err != nil {
2046: 			// Since key handles are unique, no need to check other devices.
2047: 			return trace.AccessDenied("U2F response validation failed for device %q: %v", dev.GetName(), err)
2048: 		}
2049: 		return nil
2050: 	}
