1423: func (g *GRPCServer) DeleteMFADevice(stream proto.AuthService_DeleteMFADeviceServer) error {
1424: 	ctx := stream.Context()
1425: 	actx, err := g.authenticate(ctx)
1426: 	if err != nil {
1427: 		return trail.ToGRPC(err)
1428: 	}
1429: 	auth := actx.authServer
1430: 	user := actx.User.GetName()
1431: 
1432: 	// The RPC is streaming both ways and the message sequence is:
1433: 	// (-> means client-to-server, <- means server-to-client)
1434: 	//
1435: 	// 1. -> Init
1436: 	// 2. <- MFAChallenge
1437: 	// 3. -> MFAResponse
1438: 	// 4. <- Ack
1439: 
1440: 	// 1. receive client Init
1441: 	req, err := stream.Recv()
1442: 	if err != nil {
1443: 		return trail.ToGRPC(err)
1444: 	}
1445: 	initReq := req.GetInit()
1446: 	if initReq == nil {
1447: 		return trail.ToGRPC(trace.BadParameter("expected DeleteMFADeviceRequestInit, got %T", req))
1448: 	}
1449: 
1450: 	// 2. send MFAAuthenticateChallenge
1451: 	// 3. receive and validate MFAAuthenticateResponse
1452: 	if err := deleteMFADeviceAuthChallenge(actx, stream); err != nil {
1453: 		return trail.ToGRPC(err)
1454: 	}
1455: 
1456: 	// Find the device and delete it from backend.
1457: 	devs, err := auth.GetMFADevices(ctx, user)
1458: 	if err != nil {
1459: 		return trace.Wrap(err)
1460: 	}
1461: 	for _, d := range devs {
1462: 		// Match device by name or ID.
1463: 		if d.Metadata.Name != initReq.DeviceName && d.Id != initReq.DeviceName {
1464: 			continue
1465: 		}
1466: 		if err := auth.DeleteMFADevice(ctx, user, d.Id); err != nil {
1467: 			return trail.ToGRPC(err)
1468: 		}
1469: 		// 4. send Ack
1470: 		if err := stream.Send(&proto.DeleteMFADeviceResponse{
1471: 			Response: &proto.DeleteMFADeviceResponse_Ack{Ack: &proto.DeleteMFADeviceResponseAck{}},
1472: 		}); err != nil {
1473: 			return trail.ToGRPC(err)
1474: 		}
1475: 		return nil
1476: 	}
1477: 	return trail.ToGRPC(trace.NotFound("MFA device %q does not exist", initReq.DeviceName))
1478: }
