)

// TestRegression_MultiDeviceU2FAuthentication tests that multiple U2F devices can be registered
// and used interchangeably during authentication. This is a regression test for the bug where
// only a single U2F device was recognized even when multiple devices were registered.
func TestRegression_MultiDeviceU2FAuthentication(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Set up auth server with U2F enabled
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.U2F,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "u2f-user", []string{"role"})
	require.NoError(t, err)
	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	username := user.GetName()

	// Store registered U2F devices
	u2fDevices := make(map[string]*mocku2f.Key)

	// Register first U2F device
	t.Run("register_first_u2f_device", func(t *testing.T) {
		addStream, err := cl.AddMFADevice(ctx)
		require.NoError(t, err)

		// Send init request
		err = addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_Init{
				Init: &proto.AddMFADeviceRequestInit{
					DeviceName: "u2f-device-1",
					Type:       proto.AddMFADeviceRequestInit_U2F,
				},
			},
		})
		require.NoError(t, err)

		// Receive and handle MFA challenge (should be empty for first device)
		resp, err := addStream.Recv()
		require.NoError(t, err)
		challenge := resp.GetExistingMFAChallenge()
		require.NotNil(t, challenge)
		require.Nil(t, challenge.TOTP)
		require.Empty(t, challenge.U2F)

		// Send empty response (no auth needed for first device)
		err = addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
				ExistingMFAResponse: &proto.MFAAuthenticateResponse{},
			},
		})
		require.NoError(t, err)

		// Receive registration challenge
		resp, err = addStream.Recv()
		require.NoError(t, err)
		regChallenge := resp.GetNewMFARegisterChallenge()
		require.NotNil(t, regChallenge)
		u2fChallenge := regChallenge.GetU2F()
		require.NotNil(t, u2fChallenge)

		// Create a U2F device and register it
		mdev, err := mocku2f.Create()
		require.NoError(t, err)
		u2fDevices["u2f-device-1"] = mdev

		mresp, err := mdev.RegisterResponse(&u2f.RegisterChallenge{
			Challenge: u2fChallenge.Challenge,
			AppID:     u2fChallenge.AppID,
		})
		require.NoError(t, err)

		err = addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
				NewMFARegisterResponse: &proto.MFARegisterResponse{
					Response: &proto.MFARegisterResponse_U2F{
						U2F: &proto.U2FRegisterResponse{
							RegistrationData: mresp.RegistrationData,
							ClientData:       mresp.ClientData,
						},
					},
				},
			},
		})
		require.NoError(t, err)

		// Receive acknowledgement
		resp, err = addStream.Recv()
		require.NoError(t, err)
		ack := resp.GetAck()
		require.NotNil(t, ack)
		require.NotNil(t, ack.Device)
	})

	// Register second U2F device
	t.Run("register_second_u2f_device", func(t *testing.T) {
		// For second device, we need to authenticate with the first device
		addStream, err := cl.AddMFADevice(ctx)
		require.NoError(t, err)

		err = addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_Init{
				Init: &proto.AddMFADeviceRequestInit{
					DeviceName: "u2f-device-2",
					Type:       proto.AddMFADeviceRequestInit_U2F,
				},
			},
		})
		require.NoError(t, err)

		// Receive MFA challenge
		resp, err := addStream.Recv()
		require.NoError(t, err)
		challenge := resp.GetExistingMFAChallenge()
		require.NotNil(t, challenge)

		// CRITICAL: Should have exactly ONE U2F challenge for the first device
		require.Len(t, challenge.U2F, 1, "expected one U2F challenge for the registered device")

		chal := challenge.U2F[0]
		mdev := u2fDevices["u2f-device-1"]
		mresp, err := mdev.SignResponse(&u2f.AuthenticateChallenge{
			Challenge: chal.Challenge,
			KeyHandle: chal.KeyHandle,
			AppID:     chal.AppID,
		})
		require.NoError(t, err)

		err = addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
				ExistingMFAResponse: &proto.MFAAuthenticateResponse{
					Response: &proto.MFAAuthenticateResponse_U2F{
						U2F: &proto.U2FResponse{
							KeyHandle:  mresp.KeyHandle,
							ClientData: mresp.ClientData,
							Signature:  mresp.SignatureData,
						},
					},
				},
			},
		})
		require.NoError(t, err)

		// Receive registration challenge
		resp, err = addStream.Recv()
		require.NoError(t, err)
		regChallenge := resp.GetNewMFARegisterChallenge()
		require.NotNil(t, regChallenge)
		u2fChallenge := regChallenge.GetU2F()
		require.NotNil(t, u2fChallenge)

		// Create and register second U2F device
		mdev2, err := mocku2f.Create()
		require.NoError(t, err)
		u2fDevices["u2f-device-2"] = mdev2

		mresp2, err := mdev2.RegisterResponse(&u2f.RegisterChallenge{
			Challenge: u2fChallenge.Challenge,
			AppID:     u2fChallenge.AppID,
		})
		require.NoError(t, err)

		err = addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
				NewMFARegisterResponse: &proto.MFARegisterResponse{
					Response: &proto.MFARegisterResponse_U2F{
						U2F: &proto.U2FRegisterResponse{
							RegistrationData: mresp2.RegistrationData,
							ClientData:       mresp2.ClientData,
						},
					},
				},
			},
		})
		require.NoError(t, err)

		resp, err = addStream.Recv()
		require.NoError(t, err)
		ack := resp.GetAck()
		require.NotNil(t, ack)
	})

	// Verify both devices are registered
	t.Run("verify_devices_registered", func(t *testing.T) {
		devicesResp, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
		require.NoError(t, err)
		require.Len(t, devicesResp.Devices, 2, "expected exactly 2 U2F devices to be registered")

		deviceNames := make(map[string]bool)
		for _, dev := range devicesResp.Devices {
			deviceNames[dev.GetName()] = true
		}
		require.True(t, deviceNames["u2f-device-1"])
		require.True(t, deviceNames["u2f-device-2"])
	})

	// Test multi-device authentication with both devices
	t.Run("authenticate_with_first_device", func(t *testing.T) {
		// Get MFA authenticate challenge for login
		u2fStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err)

		challenge, err := as.AuthServer.mfaAuthChallenge(ctx, username, u2fStorage)
		require.NoError(t, err)

		// CRITICAL BUG TEST: Should have challenges for BOTH devices
		require.Len(t, challenge.U2F, 2, "expected challenges for both U2F devices, but got %d", len(challenge.U2F))

		// Authenticate with the first device
		firstChal := challenge.U2F[0]
		mdev1 := u2fDevices["u2f-device-1"]
		resp, err := mdev1.SignResponse(&u2f.AuthenticateChallenge{
			Challenge: firstChal.Challenge,
			KeyHandle: firstChal.KeyHandle,
			AppID:     firstChal.AppID,
		})
		require.NoError(t, err)

		// Validate the response
		err = as.AuthServer.checkU2F(ctx, username, u2f.AuthenticateChallengeResponse{
			KeyHandle:     resp.KeyHandle,
			ClientData:    resp.ClientData,
			SignatureData: resp.SignatureData,
		}, u2fStorage)
		require.NoError(t, err, "authentication with first device should succeed")
	})

	t.Run("authenticate_with_second_device", func(t *testing.T) {
		// Get fresh MFA authenticate challenge
		u2fStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err)

		challenge, err := as.AuthServer.mfaAuthChallenge(ctx, username, u2fStorage)
		require.NoError(t, err)

		// CRITICAL BUG TEST: Should have challenges for BOTH devices
		require.Len(t, challenge.U2F, 2, "expected challenges for both U2F devices")

		// Authenticate with the second device (which is different from the first)
		var secondChal *proto.U2FChallenge
		var firstChalKeyHandle string

		mdev1KeyHandle := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(
			u2fDevices["u2f-device-1"].KeyHandle)

		// Find the challenge for the second device
		for _, c := range challenge.U2F {
			if c.KeyHandle == mdev1KeyHandle {
				firstChalKeyHandle = c.KeyHandle
			} else {
				secondChal = c
			}
		}

		require.NotNil(t, secondChal, "should have found a challenge for the second device")
		require.NotEmpty(t, firstChalKeyHandle, "should have found a challenge for the first device")

		// Respond with the second device
		mdev2 := u2fDevices["u2f-device-2"]
		resp, err := mdev2.SignResponse(&u2f.AuthenticateChallenge{
			Challenge: secondChal.Challenge,
			KeyHandle: secondChal.KeyHandle,
			AppID:     secondChal.AppID,
		})
		require.NoError(t, err)

		// Validate the response
		err = as.AuthServer.checkU2F(ctx, username, u2f.AuthenticateChallengeResponse{
			KeyHandle:     resp.KeyHandle,
			ClientData:    resp.ClientData,
			SignatureData: resp.SignatureData,
		}, u2fStorage)
		require.NoError(t, err, "authentication with second device should succeed")
	})

	// Test deleting first device still allows second device authentication
	t.Run("delete_first_device_use_second", func(t *testing.T) {
		deleteStream, err := cl.DeleteMFADevice(ctx)
		require.NoError(t, err)

		err = deleteStream.Send(&proto.DeleteMFADeviceRequest{
			Request: &proto.DeleteMFADeviceRequest_Init{
				Init: &proto.DeleteMFADeviceRequestInit{
					DeviceName: "u2f-device-1",
				},
			},
		})
		require.NoError(t, err)

		// Get MFA challenge for deletion
		resp, err := deleteStream.Recv()
		require.NoError(t, err)
		challenge := resp.GetMFAChallenge()
		require.NotNil(t, challenge)

		// Should now have only ONE U2F challenge (for the remaining device)
		require.Len(t, challenge.U2F, 1, "after deletion, should only have challenge for remaining device")

		chal := challenge.U2F[0]
		mdev2 := u2fDevices["u2f-device-2"]
		mresp, err := mdev2.SignResponse(&u2f.AuthenticateChallenge{
			Challenge: chal.Challenge,
			KeyHandle: chal.KeyHandle,
			AppID:     chal.AppID,
		})
		require.NoError(t, err)

		err = deleteStream.Send(&proto.DeleteMFADeviceRequest{
			Request: &proto.DeleteMFADeviceRequest_MFAResponse{
				MFAResponse: &proto.MFAAuthenticateResponse{
					Response: &proto.MFAAuthenticateResponse_U2F{
						U2F: &proto.U2FResponse{
							KeyHandle:  mresp.KeyHandle,
							ClientData: mresp.ClientData,
							Signature:  mresp.SignatureData,
						},
					},
				},
			},
		})
		require.NoError(t, err)

		resp, err = deleteStream.Recv()
		require.NoError(t, err)
		require.NotNil(t, resp.GetAck())
	})

	// Test the web API path for U2F (legacy single-device format)
	t.Run("webapi_u2f_sign_request_backwards_compat", func(t *testing.T) {
		// Use the legacy U2FSignRequest method (used by web clients)
		signReq, err := as.AuthServer.U2FSignRequest(username, []byte("test-password"))
		require.NoError(t, err)
		require.NotNil(t, signReq)

		// Should have the single-device AuthenticateChallenge for backwards compatibility
		require.NotNil(t, signReq.AuthenticateChallenge, "old clients expect embedded challenge")

		// NEW: Should also have all challenges for new clients
		// CRITICAL BUG TEST: Should have challenges for all registered U2F devices
		require.Len(t, signReq.Challenges, 1, "after deleting first device, should have 1 challenge")

		// Verify the old-format challenge matches first challenge in new format
		require.Equal(t, signReq.AuthenticateChallenge.Challenge, signReq.Challenges[0].Challenge)
	})
}

// TestRegression_U2FClientServerVersionCompat tests that older clients can authenticate
// with newer servers and vice versa.
func TestRegression_U2FClientServerVersionCompat(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Set up auth server with U2F enabled
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.U2F,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "compat-user", []string{"role"})
	require.NoError(t, err)
	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	username := user.GetName()

	// Register a U2F device
	u2fStorage, err := u2f.InMemoryRegistrationStorage(as.AuthServer.Identity)
	require.NoError(t, err)

	regChallenge, err := u2f.RegisterInit(u2f.RegisterInitParams{
		StorageKey: username,
		AppConfig: types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
		Storage: u2fStorage,
	})
	require.NoError(t, err)

	mdev, err := mocku2f.Create()
	require.NoError(t, err)

	regResp, err := mdev.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: regChallenge.Challenge,
		AppID:     regChallenge.AppID,
	})
	require.NoError(t, err)

	dev, err := u2f.NewDevice(username, &u2f.Registration{
		KeyHandle: mdev.KeyHandle,
		PubKey:    mdev.PrivateKey.PublicKey,
	}, clock.Now())
	require.NoError(t, err)

	err = as.AuthServer.UpsertMFADevice(ctx, username, dev)
	require.NoError(t, err)

	t.Run("old_client_new_server", func(t *testing.T) {
		// Old client expects embedded AuthenticateChallenge
		// New server sends AuthenticateChallenge + Challenges array
		signReq, err := as.AuthServer.U2FSignRequest(username, []byte("test-password"))
		require.NoError(t, err)

		// Old clients only read the embedded field
		require.NotNil(t, signReq.AuthenticateChallenge)
		oldClientChallenge := signReq.AuthenticateChallenge

		// Old client should be able to use this challenge
		resp, err := mdev.SignResponse(oldClientChallenge)
		require.NoError(t, err)

		// Should authenticate successfully
		authStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err)

		err = as.AuthServer.CheckU2FSignResponse(ctx, username, resp)
		require.NoError(t, err)
	})

	t.Run("new_client_old_server_format", func(t *testing.T) {
		// Simulate old server sending just the embedded field
		signReq, err := as.AuthServer.U2FSignRequest(username, []byte("test-password"))
		require.NoError(t, err)

		// Simulate old server format (only AuthenticateChallenge, empty Challenges)
		oldServerFormat := &auth.U2FAuthenticateChallenge{
			AuthenticateChallenge: signReq.AuthenticateChallenge,
			Challenges:            nil, // Old server didn't send this
		}

		// New client should fall back to using embedded challenge
		if len(oldServerFormat.Challenges) == 0 && oldServerFormat.AuthenticateChallenge != nil {
			// New client logic: fall back to old format
			oldServerFormat.Challenges = []u2f.AuthenticateChallenge{*oldServerFormat.AuthenticateChallenge}
		}

		require.Len(t, oldServerFormat.Challenges, 1)

		// New client should be able to use this
		chal := oldServerFormat.Challenges[0]
		resp, err := mdev.SignResponse(&chal)
		require.NoError(t, err)

		authStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err)

		err = as.AuthServer.CheckU2FSignResponse(ctx, username, resp)
		require.NoError(t, err)
	})
}

// TestRegression_U2FSignChallengeBackwardsCompat tests the JSON marshaling
// compatibility for U2FAuthenticateChallenge between old and new formats.
func TestRegression_U2FSignChallengeBackwardsCompat(t *testing.T) {
	// This test checks the compatibility layer between old and new challenge formats
	// as described in auth.go:TestU2FSignChallengeCompat

	// Test data
	newChallenge := &auth.U2FAuthenticateChallenge{
		AuthenticateChallenge: &u2f.AuthenticateChallenge{
			Challenge: "c1",
		},
		Challenges: []u2f.AuthenticateChallenge{
			{Challenge: "c1"},
			{Challenge: "c2"},
			{Challenge: "c3"},
		},
	}

	t.Run("new_challenge_old_client", func(t *testing.T) {
		// New server sends new format, old client receives it
		// Old client only has AuthenticateChallenge field
		var oldChallenge u2f.AuthenticateChallenge

		// Simulate JSON wire format
		newJSON := newChallenge.AuthenticateChallenge
